import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./ExpenseUI.css";

function AddTicket({ employee }) {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    ticket_date: "",
    purpose: "",
    assigned_to: "",
    amount: "",
  });

  const saveTicket = async () => {
    try {
      await fetch("https://prasa-backend-1.onrender.com/ticket/add", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...form, empld: employee?.empld }),
      });

      alert("Ticket Expense Added!");

      setForm({
        ticket_date: "",
        purpose: "",
        assigned_to: "",
        amount: "",
      });
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div className="expense-container">

      {/* BACK BUTTON FIXED */}
      <div className="back-btn" onClick={() => navigate("/add")}>
        ← Back
      </div>

      <h2 className="page-title">Ticket Expense</h2>

      <div className="expense-card">

        <div className="grid-3">

          <input
            type="date"
            value={form.ticket_date}
            onChange={(e) =>
              setForm({ ...form, ticket_date: e.target.value })
            }
            className="input-box"
          />

          <input
            type="text"
            placeholder="Purpose"
            value={form.purpose}
            onChange={(e) =>
              setForm({ ...form, purpose: e.target.value })
            }
            className="input-box"
          />

          <input
            type="text"
            placeholder="Assigned To"
            value={form.assigned_to}
            onChange={(e) =>
              setForm({ ...form, assigned_to: e.target.value })
            }
            className="input-box"
          />

          <input
            type="number"
            placeholder="Amount"
            value={form.amount}
            onChange={(e) =>
              setForm({ ...form, amount: e.target.value })
            }
            className="input-box"
          />
        </div>

        <button className="save-btn" onClick={saveTicket}>
          Save Ticket Expense
        </button>
      </div>
    </div>
  );
}

export default AddTicket;
